import{_ as e,o as i,c as r,ag as o}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"Identity Providers","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/identity-providers.md","filePath":"admin-ui/identity-providers.md"}'),d={name:"admin-ui/identity-providers.md"};function a(n,t,s,l,c,h){return i(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="identity-providers" tabindex="-1">Identity Providers <a class="header-anchor" href="#identity-providers" aria-label="Permalink to &quot;Identity Providers&quot;">​</a></h1><p>The Identity Providers page manages external authentication sources (SAML, OIDC, social logins) integrated through Keycloak. This enables federated login so users can authenticate with their existing institutional credentials.</p><h2 id="accessing" tabindex="-1">Accessing <a class="header-anchor" href="#accessing" aria-label="Permalink to &quot;Accessing&quot;">​</a></h2><p>Navigate to <strong>Identity Providers</strong> in the admin sidebar.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="provider-list" tabindex="-1">Provider List <a class="header-anchor" href="#provider-list" aria-label="Permalink to &quot;Provider List&quot;">​</a></h3><p>The main view shows all configured identity providers with:</p><ul><li>Provider alias and display name</li><li>Provider type (SAML, OIDC, Google, Microsoft, etc.)</li><li>Enabled/disabled status</li><li>Provider count summary (enabled vs total)</li></ul><h3 id="adding-a-provider" tabindex="-1">Adding a Provider <a class="header-anchor" href="#adding-a-provider" aria-label="Permalink to &quot;Adding a Provider&quot;">​</a></h3><p>Click <strong>Add Identity Provider</strong> to configure a new external authentication source:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Alias</strong></td><td>Unique identifier for the provider (used in URLs)</td></tr><tr><td><strong>Display Name</strong></td><td>User-facing name shown on the login page</td></tr><tr><td><strong>Provider Type</strong></td><td>Protocol — <code>saml</code>, <code>oidc</code>, <code>google</code>, <code>microsoft</code>, etc.</td></tr><tr><td><strong>Enabled</strong></td><td>Whether the provider is active</td></tr><tr><td><strong>Trust Email</strong></td><td>Trust email addresses from this provider without verification</td></tr><tr><td><strong>Store Token</strong></td><td>Store the external token for later use</td></tr><tr><td><strong>Link Only</strong></td><td>Only link accounts, don&#39;t create new users</td></tr><tr><td><strong>Hide on Login</strong></td><td>Hide from the login page (for programmatic linking only)</td></tr><tr><td><strong>First Broker Login Flow</strong></td><td>Authentication flow for first-time federated users</td></tr><tr><td><strong>Post Broker Login Flow</strong></td><td>Authentication flow after broker login</td></tr></tbody></table><h3 id="provider-configuration" tabindex="-1">Provider Configuration <a class="header-anchor" href="#provider-configuration" aria-label="Permalink to &quot;Provider Configuration&quot;">​</a></h3><p>Each provider type has specific configuration fields in the <code>config</code> object:</p><h4 id="oidc-providers" tabindex="-1">OIDC Providers <a class="header-anchor" href="#oidc-providers" aria-label="Permalink to &quot;OIDC Providers&quot;">​</a></h4><ul><li>Authorization URL, Token URL, Logout URL</li><li>Client ID and Client Secret</li><li>Scopes, PKCE method</li><li>Issuer, JWKS URL</li></ul><h4 id="saml-providers" tabindex="-1">SAML Providers <a class="header-anchor" href="#saml-providers" aria-label="Permalink to &quot;SAML Providers&quot;">​</a></h4><ul><li>SSO Service URL, Entity ID</li><li>Signing and encryption certificates</li><li>NameID format, binding type</li></ul><h3 id="connection-testing" tabindex="-1">Connection Testing <a class="header-anchor" href="#connection-testing" aria-label="Permalink to &quot;Connection Testing&quot;">​</a></h3><p>Test the connection to an identity provider to verify configuration without affecting production logins.</p><h3 id="editing-and-deleting" tabindex="-1">Editing and Deleting <a class="header-anchor" href="#editing-and-deleting" aria-label="Permalink to &quot;Editing and Deleting&quot;">​</a></h3><ul><li>Click a provider to edit its configuration</li><li>Delete removes the provider and breaks any linked user accounts</li></ul><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/idps/count</code></td><td>Count enabled and total providers</td></tr><tr><td><code>GET</code></td><td><code>/admin/idps/</code></td><td>List all identity providers</td></tr><tr><td><code>POST</code></td><td><code>/admin/idps/</code></td><td>Create a new identity provider</td></tr><tr><td><code>GET</code></td><td><code>/admin/idps/:alias</code></td><td>Get provider details</td></tr><tr><td><code>PUT</code></td><td><code>/admin/idps/:alias</code></td><td>Update provider configuration</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/idps/:alias</code></td><td>Delete a provider</td></tr></tbody></table><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li><strong>Enterprise SSO</strong> — Connect to hospital Active Directory via SAML or OIDC</li><li><strong>Social Login</strong> — Allow patients to sign in with Google or Apple accounts</li><li><strong>Multi-organization</strong> — Different identity providers per organization for federated access</li><li><strong>Identity Brokering</strong> — Chain multiple providers through Keycloak&#39;s brokering flows</li></ul>',25)])])}const p=e(d,[["render",a]]);export{u as __pageData,p as default};
